import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../data/api';
import { useAuth } from '../context/AuthContext';
import XPBar from '../components/XPBar';

const s = {
  page: { padding: '2rem', maxWidth: '1100px', margin: '0 auto' },
  title: { fontSize: '1.8rem', fontWeight: 700, color: '#fff' },
  sub: { color: '#888', marginTop: '0.3rem', marginBottom: '1.5rem' },
  statsRow: { display: 'flex', gap: '1rem', marginBottom: '1.5rem', flexWrap: 'wrap' },
  statCard: { background: '#1a1a2e', border: '1px solid #2a2a4a', borderRadius: '10px', padding: '1rem 1.5rem', textAlign: 'center', minWidth: '100px' },
  statVal: { fontSize: '1.5rem', fontWeight: 700, color: '#7c6af7' },
  statLabel: { color: '#888', fontSize: '0.8rem' },
  toolbar: { display: 'flex', gap: '0.75rem', marginBottom: '1.5rem', flexWrap: 'wrap', alignItems: 'center' },
  search: { flex: 1, minWidth: '200px', padding: '0.6rem 1rem', background: '#1a1a2e', border: '1px solid #2a2a4a', borderRadius: '8px', color: '#e0e0e0', fontSize: '0.9rem', outline: 'none' },
  filterBtn: { padding: '0.5rem 1rem', borderRadius: '20px', border: '1px solid #2a2a4a', cursor: 'pointer', fontSize: '0.85rem', background: 'none', color: '#888' },
  activeFilter: { background: '#7c6af7', color: '#fff', border: '1px solid #7c6af7' },
  grid: { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(220px, 1fr))', gap: '1.5rem' },
  card: { background: '#1a1a2e', borderRadius: '12px', padding: '1.5rem', cursor: 'pointer', border: '1px solid #2a2a4a', transition: 'border-color 0.2s', position: 'relative' },
  icon: { fontSize: '2.5rem', marginBottom: '0.75rem' },
  lang: { fontSize: '1.1rem', fontWeight: 700, color: '#fff', marginBottom: '0.3rem' },
  desc: { color: '#888', fontSize: '0.85rem', marginBottom: '1rem' },
  levels: { display: 'flex', gap: '0.4rem', flexWrap: 'wrap' },
  badge: { padding: '0.2rem 0.6rem', borderRadius: '20px', fontSize: '0.75rem', fontWeight: 600 },
  enrolledBadge: { position: 'absolute', top: '0.75rem', right: '0.75rem', background: '#4caf5022', color: '#4caf50', padding: '0.2rem 0.5rem', borderRadius: '20px', fontSize: '0.7rem', fontWeight: 600 },
  sectionTitle: { color: '#fff', fontWeight: 700, fontSize: '1.1rem', marginBottom: '1rem', marginTop: '0.5rem' },
  empty: { color: '#555', padding: '2rem', textAlign: 'center', background: '#1a1a2e', borderRadius: '10px', border: '1px solid #2a2a4a' },
};

const levelColors = { beginner: '#4caf50', intermediate: '#ff9800', advanced: '#f44336' };
const languages = ['All', 'Python', 'Java', 'C', 'C++', 'JavaScript'];

export default function Dashboard() {
  const [courses, setCourses] = useState([]);
  const [search, setSearch] = useState('');
  const [filter, setFilter] = useState('All');
  const [enrolledIds, setEnrolledIds] = useState([]);
  const { user } = useAuth();
  const navigate = useNavigate();

  useEffect(() => {
    api.get('/courses').then(r => setCourses(r.data));
    api.get('/auth/me').then(r => setEnrolledIds((r.data.enrolledCourses || []).map(c => c._id || c)));
  }, []);

  const enroll = async (e, courseId) => {
    e.stopPropagation();
    await api.post(`/users/enroll/${courseId}`);
    setEnrolledIds(prev => [...prev, courseId]);
  };

  const filtered = courses.filter(c => {
    const matchSearch = c.title.toLowerCase().includes(search.toLowerCase());
    const matchFilter = filter === 'All' || c.title.toLowerCase().includes(filter.toLowerCase());
    return matchSearch && matchFilter;
  });

  const enrolled = filtered.filter(c => enrolledIds.includes(c._id));
  const all = filtered.filter(c => !enrolledIds.includes(c._id));

  return (
    <div style={s.page}>
      <div style={s.title}>Welcome back, {user?.name} 👋</div>
      <div style={s.sub}>Pick a course and start coding</div>

      <XPBar xp={user?.xp || 0} />

      <div style={s.statsRow}>
        <div style={s.statCard}><div style={s.statVal}>🔥 {user?.streak}</div><div style={s.statLabel}>Day Streak</div></div>
        <div style={s.statCard}><div style={s.statVal}>⭐ {user?.xp}</div><div style={s.statLabel}>Total XP</div></div>
        <div style={s.statCard}><div style={s.statVal}>{user?.certificates?.length || 0}</div><div style={s.statLabel}>Certificates</div></div>
        <div style={s.statCard}><div style={s.statVal}>{enrolledIds.length}</div><div style={s.statLabel}>Enrolled</div></div>
      </div>

      <div style={s.toolbar}>
        <input style={s.search} placeholder="🔍 Search courses..." value={search} onChange={e => setSearch(e.target.value)} />
        {languages.map(l => (
          <button key={l} style={filter === l ? { ...s.filterBtn, ...s.activeFilter } : s.filterBtn} onClick={() => setFilter(l)}>{l}</button>
        ))}
      </div>

      {enrolled.length > 0 && (
        <>
          <div style={s.sectionTitle}>📌 My Courses</div>
          <div style={{ ...s.grid, marginBottom: '2rem' }}>
            {enrolled.map(course => <CourseCard key={course._id} course={course} enrolled navigate={navigate} onEnroll={enroll} />)}
          </div>
        </>
      )}

      <div style={s.sectionTitle}>{enrolled.length > 0 ? '🌐 All Courses' : '🌐 Courses'}</div>
      {all.length === 0 && enrolled.length === 0
        ? <div style={s.empty}>No courses found</div>
        : <div style={s.grid}>{all.map(course => <CourseCard key={course._id} course={course} enrolled={false} navigate={navigate} onEnroll={enroll} />)}</div>
      }
    </div>
  );
}

function CourseCard({ course, enrolled, navigate, onEnroll }) {
  return (
    <div style={{ ...s.card, borderColor: course.color + '44' }}
      onClick={() => navigate(`/course/${course._id}`)}
      onMouseEnter={e => e.currentTarget.style.borderColor = course.color}
      onMouseLeave={e => e.currentTarget.style.borderColor = course.color + '44'}>
      {enrolled && <span style={s.enrolledBadge}>✅ Enrolled</span>}
      <div style={s.icon}>{course.icon}</div>
      <div style={s.lang}>{course.title}</div>
      <div style={s.desc}>{course.description}</div>
      <div style={s.levels}>
        {['beginner', 'intermediate', 'advanced'].map(l => (
          <span key={l} style={{ ...s.badge, background: levelColors[l] + '22', color: levelColors[l] }}>{l}</span>
        ))}
      </div>
      {!enrolled && (
        <button style={{ marginTop: '1rem', width: '100%', padding: '0.4rem', background: '#7c6af722', color: '#7c6af7', border: '1px solid #7c6af7', borderRadius: '6px', cursor: 'pointer', fontSize: '0.85rem', fontWeight: 600 }}
          onClick={e => onEnroll(e, course._id)}>
          + Enroll
        </button>
      )}
    </div>
  );
}
